import { AngleSlider as ArkAngleSlider } from "@ark-ui/react/angle-slider";
import { Circle } from "lucide-react";

import { cn } from "@/lib/utils";

import type {
  AngleSliderRootProps,
  AngleSliderLabelProps,
  AngleSliderControlProps,
  AngleSliderThumbProps,
  AngleSliderMarkerGroupProps,
  AngleSliderMarkerProps,
  AngleSliderValueTextProps,
  AngleSliderHiddenInputProps,
} from "@ark-ui/react";

const AngleSliderRoot = ({ className, ...rest }: AngleSliderRootProps) => (
  <ArkAngleSlider.Root
    className={cn(
      "flex flex-col items-center gap-4 w-fit relative",
      className,
    )}
    {...rest}
  />
);

const AngleSliderLabel = ({ className, ...rest }: AngleSliderLabelProps) => (
  <ArkAngleSlider.Label
    className={cn(
      "text-lg font-semibold text-gray-800",
      "mb-2",
      className,
    )}
    {...rest}
  />
);

const AngleSliderControl = ({ className, ...rest }: AngleSliderControlProps) => (
  <ArkAngleSlider.Control
    className={cn(
      "relative w-[200px] h-[200px]",
      "bg-white rounded-full",
      "flex items-center justify-center",
      className,
    )}
    {...rest}
  >
    {/* Outer ring with conic gradient for progress */}
    <div
      className="absolute inset-0 rounded-full"
      style={{
        background: `conic-gradient(from 0deg, rgb(34 197 94 / 0.5) var(--angle, 0deg), rgb(229 231 235) var(--angle, 0deg))`,
      }}
    />

    {/* Inner white circle to create ring effect */}
    <div className="absolute inset-4 bg-white rounded-full" />
  </ArkAngleSlider.Control>
);

const AngleSliderThumb = ({ className, ...rest }: AngleSliderThumbProps) => (
  <ArkAngleSlider.Thumb
    className={cn(
      "absolute top-10 z-50 w-5 h-5 bg-green-500 rounded-full",
      className,
    )}
    {...rest}
  />
)

const AngleSliderMarkerGroup = ({ className, ...rest }: AngleSliderMarkerGroupProps) => (
  <ArkAngleSlider.MarkerGroup
    className={cn(
      "absolute inset-0 z-10",
      className,
    )}
    {...rest}
  />
);

const AngleSliderMarker = ({ className, value, ...rest }: AngleSliderMarkerProps) => (
  <ArkAngleSlider.Marker
    className={cn(
      "absolute w-1 h-3 -translate-x-1/2",
      "bg-gray-600 rounded-sm",
      "origin-bottom",
      className,
    )}
    value={value}
    {...rest}
  />
);

const AngleSliderValueText = ({ className, ...rest }: AngleSliderValueTextProps) => (
  <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-30">
    <ArkAngleSlider.ValueText
      className={cn(
        "text-2xl font-bold text-gray-800",
        "text-center",
        className,
      )}
      {...rest}
    />
  </div>
);

const AngleSliderHiddenInput = ({ className, ...rest }: AngleSliderHiddenInputProps) => (
  <ArkAngleSlider.HiddenInput
    className={cn(className)}
    {...rest}
  />
);

export {
  AngleSliderRoot,
  AngleSliderLabel,
  AngleSliderControl,
  AngleSliderThumb,
  AngleSliderMarkerGroup,
  AngleSliderMarker,
  AngleSliderValueText,
  AngleSliderHiddenInput,
};

import { clsx } from "clsx";
import { twMerge } from "tailwind-merge";

import type { ClassValue } from "clsx";

export const cn = (...inputs: ClassValue[]) => {
  return twMerge(clsx(inputs));
};
